253	/// Validate an `fopen` mode string: must match `[rwa]\+?b*`. C: `l_checkmode`.
254	///
255	/// C: `return (*mode != '\0' && strchr("rwa", *(mode++)) != NULL &&
256	///           (*mode != '+' || ...) && strspn(mode, "b") == strlen(mode));`
257	fn check_mode(mode: &[u8]) -> bool {
258	    if mode.is_empty() {
259	        return false;
260	    }
261	    let mut idx = 0usize;
262	    if !matches!(mode[idx], b'r' | b'w' | b'a') {
263	        return false;
264	    }
265	    idx += 1;
266	    if idx < mode.len() && mode[idx] == b'+' {
267	        idx += 1;
268	    }
269	    mode[idx..].iter().all(|&b| b == b'b')
270	}
271	
272	/// Validate a `popen` mode string: only `"r"` or `"w"`. C: `l_checkmodep`.
273	fn check_mode_popen(mode: &[u8]) -> bool {
274	    matches!(mode, b"r" | b"w")
275	}
