277	/// Push success (`true`) or failure (`false`, msg, errno) per `luaL_fileresult`.
278	///
279	/// C: `if (stat) { lua_pushboolean(L,1); return 1; }
280	///     else { luaL_pushfail; pushstring(msg); pushinteger(errno); return 3; }`
281	fn file_result(
282	    state: &mut LuaState,
283	    success: bool,
284	    fname: Option<&[u8]>,
285	    os_err: io::Error,
286	) -> Result<usize, LuaError> {
287	    if success {
288	        // C: lua_pushboolean(L, 1); return 1;
289	        state.push(LuaValue::Bool(true));
290	        return Ok(1);
291	    }
292	    // C: luaL_pushfail(L)  — Lua 5.4 pushfail = push false
293	    state.push(LuaValue::Bool(false));
294	    // C: msg = strerror(errno); if (fname) lua_pushfstring(L, "%s: %s", fname, msg);
295	    let msg = os_err.to_string();
296	    match fname {
297	        Some(name) => {
298	            let mut s = Vec::with_capacity(name.len() + 2 + msg.len());
299	            s.extend_from_slice(name);
300	            s.extend_from_slice(b": ");
301	            s.extend_from_slice(msg.as_bytes());
302	            state.push_string(&s);
303	        }
304	        None => {
305	            state.push_string(msg.as_bytes());
306	        }
307	    }
308	    // C: lua_pushinteger(L, en)
309	    let errno_code = os_err.raw_os_error().unwrap_or(0) as i64;
310	    state.push(LuaValue::Int(errno_code));
311	    Ok(3)
312	}
