391	/// Open `fname` and push its handle; raise a runtime error on failure.
392	/// C: `opencheck(L, fname, mode)`.
393	///
394	/// TODO(port): std::fs::File::open needed.
395	fn opencheck(state: &mut LuaState, fname: &[u8], mode: &[u8]) -> Result<(), LuaError> {
396	    // C: LStream *p = newfile(L); p->f = fopen(fname, mode);
397	    // C: if (p->f == NULL) luaL_error(L, "cannot open file '%s' (%s)", fname, strerror(errno));
398	    new_file(state)?;
399	    // TODO(port): std::fs::File — open fname in mode, store in LStream.file
400	    let open_result: Result<Box<dyn LuaFileOps>, io::Error> = Err(io::Error::new(
401	        io::ErrorKind::Unsupported,
402	        "TODO(port): std::fs::File not yet wired",
403	    ));
404	    match open_result {
405	        Ok(_f) => {
406	            // TODO(port): store f in the just-allocated LStream.file
407	            Ok(())
408	        }
409	        Err(e) => Err(LuaError::runtime(format_args!(
410	            "cannot open file '{}' ({})",
411	            fname.escape_ascii(),
412	            e
413	        ))),
414	    }
