654	/// Read and push a Lua number from `file`. Return `true` on success.
655	/// C: `read_number(L, f)`.
656	fn read_number(
657	    state: &mut LuaState,
658	    file: &mut dyn LuaFileOps,
659	) -> Result<bool, LuaError> {
660	    // C: do { rn.c = l_getc(rn.f); } while (isspace(rn.c)); /* skip spaces */
661	    let first = loop {
662	        let b = file.read_byte();
663	        if b == EOF_SENTINEL || !(b as u8).is_ascii_whitespace() {
664	            break b;
665	        }
666	    };
667	
668	    let mut rn = ReadNumState::new(first);
669	
670	    // C: test2(&rn, "-+")
671	    rn.try2(file, [b'-', b'+']);
672	
673	    // C: if (test2(&rn, "00")) { if (test2(&rn, "xX")) hex = 1; else count = 1; }
674	    let mut count: usize = 0;
675	    let hex = if rn.try2(file, [b'0', b'0']) {
676	        if rn.try2(file, [b'x', b'X']) {
677	            true
678	        } else {
679	            count = 1;
680	            false
681	        }
682	    } else {
683	        false
684	    };
685	
686	    // C: count += readdigits(&rn, hex);
687	    count += rn.read_digits(file, hex);
688	
689	    // C: decp[0] = lua_getlocaledecpoint(); decp[1] = '.';
690	    // TODO(port): locale decimal-point character; defaulting to '.'
691	    let dec_point = b'.';
692	    if rn.try2(file, [dec_point, b'.']) {
693	        count += rn.read_digits(file, hex);
694	    }
695	
696	    // C: if (count > 0 && test2(&rn, hex ? "pP" : "eE")) { ... exponent ... }
697	    if count > 0 {
698	        let exp_chars = if hex { [b'p', b'P'] } else { [b'e', b'E'] };
699	        if rn.try2(file, exp_chars) {
700	            rn.try2(file, [b'-', b'+']);
701	            rn.read_digits(file, false);
702	        }
703	    }
704	
705	    // C: ungetc(rn.c, rn.f);
706	    file.unread_byte(rn.current);
707	
708	    // C: if (lua_stringtonumber(L, rn.buff)) return 1; else { lua_pushnil(L); return 0; }
709	    // TODO(port): state.string_to_number(bytes) — parses bytes into LuaValue::Int or Float
710	    let bytes = rn.as_bytes();
711	    let pushed = state.string_to_number_push(&bytes)?;
712	    if pushed != 0 {
713	        Ok(true)
714	    } else {
715	        state.push(LuaValue::Nil);
716	        Ok(false)
717	    }
718	}
