734	/// Read one line from `file` and push it. If `chop`, strip the trailing `\n`.
735	/// Return `true` if anything was read. C: `read_line(L, f, chop)`.
736	///
737	/// PERF(port): C uses luaL_prepbuffer (large fixed stack buffer) to avoid
738	/// per-byte allocation; Rust's Vec grows here, which is slightly slower.
739	fn read_line(
740	    state: &mut LuaState,
741	    file: &mut dyn LuaFileOps,
742	    chop: bool,
743	) -> Result<bool, LuaError> {
744	    let mut buf: Vec<u8> = Vec::new();
745	    let mut c: i32 = EOF_SENTINEL;
746	
747	    // C: do { char *buff = luaL_prepbuffer(&b); int i = 0;
748	    //          while (i < LUAL_BUFFERSIZE && (c = l_getc(f)) != EOF && c != '\n')
749	    //            buff[i++] = c;
750	    //          luaL_addsize(&b, i);
751	    //    } while (c != EOF && c != '\n');
752	    'outer: loop {
753	        for _ in 0..LUAL_BUFFER_SIZE {
754	            c = file.read_byte();
755	            if c == EOF_SENTINEL || c == b'\n' as i32 {
756	                break 'outer;
757	            }
758	            buf.push(c as u8);
759	        }
760	        // chunk full but no newline/EOF yet — continue reading
761	    }
762	
763	    // C: if (!chop && c == '\n') luaL_addchar(&b, c);
764	    if !chop && c == b'\n' as i32 {
765	        buf.push(b'\n');
766	    }
767	
768	    // C: return (c == '\n' || lua_rawlen(L, -1) > 0);
769	    let had_content = c == b'\n' as i32 || !buf.is_empty();
770	    state.push_string(&buf);
771	    Ok(had_content)
772	}
