774	/// Read the entire file into a single string and push it. C: `read_all(L, f)`.
775	///
776	/// PERF(port): C uses `fread` with a large buffer; Rust reads byte-by-byte via
777	/// `LuaFileOps::read_byte`. Phase B should add `read_chunk(&mut buf)` to the
778	/// trait for bulk reads.
779	fn read_all(state: &mut LuaState, file: &mut dyn LuaFileOps) -> Result<(), LuaError> {
780	    // C: do { nr = fread(p, LUAL_BUFFERSIZE, f); luaL_addsize(&b, nr); } while (nr == LUAL_BUFFERSIZE);
781	    let mut buf: Vec<u8> = Vec::new();
782	    loop {
783	        let start = buf.len();
784	        let mut chunk_read = 0usize;
785	        for _ in 0..LUAL_BUFFER_SIZE {
786	            let b = file.read_byte();
787	            if b == EOF_SENTINEL {
788	                break;
789	            }
790	            buf.push(b as u8);
791	            chunk_read += 1;
792	        }
793	        if chunk_read < LUAL_BUFFER_SIZE {
794	            break;
795	        }
796	    }
797	    state.push_string(&buf);
798	    Ok(())
799	}
