801	/// Read exactly `n` bytes from `file` and push the result.
802	/// Return `true` if anything was read. C: `read_chars(L, f, n)`.
803	fn read_chars(
804	    state: &mut LuaState,
805	    file: &mut dyn LuaFileOps,
806	    n: usize,
807	) -> Result<bool, LuaError> {
808	    // C: nr = fread(p, sizeof(char), n, f); luaL_addsize(&b, nr); return (nr > 0);
809	    let mut buf = Vec::with_capacity(n);
810	    for _ in 0..n {
811	        let b = file.read_byte();
812	        if b == EOF_SENTINEL {
813	            break;
814	        }
815	        buf.push(b as u8);
816	    }
817	    let nr = buf.len();
818	    state.push_string(&buf);
819	    Ok(nr > 0)
820	}
