932	/// Dispatch one or more write values. C: `g_write(L, f, arg)`.
933	///
934	/// TODO(port): borrow split — same issue as g_read.
935	fn g_write(
936	    state: &mut LuaState,
937	    file: &mut dyn LuaFileOps,
938	    arg: i32,
939	) -> Result<usize, LuaError> {
940	    // C: int nargs = lua_gettop(L) - arg;
941	    let nargs = state.top_idx().get() as i32 - arg;
942	    let mut overall_ok = true;
943	
944	    for i in 0..nargs {
945	        let idx = arg + i;
946	        if state.type_at(idx) == LuaType::Number {
947	            // C: lua_isinteger(L, arg) ? fprintf(LUA_INTEGER_FMT,...) : fprintf(LUA_NUMBER_FMT,...)
948	            // C: LUA_INTEGER_FMT = "%lld" (i64)
949	            // C: LUA_NUMBER_FMT  = "%.14g" (f64, 14 significant digits)
950	            // PERF(port): byte-by-byte write; Phase B add bulk write_fmt to LuaFileOps.
951	            // TODO(port): C's %.14g (significant digits) has no direct Rust equivalent.
952	            let s = if state.is_integer(idx) {
953	                let ival = state.to_integer(idx).unwrap_or(0);
954	                // C: LUA_INTEGER_FMT = "%lld"
955	                format!("{}", ival)
956	            } else {
957	                let fval = state.to_number(idx).unwrap_or(0.0);
958	                // C: LUA_NUMBER_FMT = "%.14g" — significant-digit format
959	                // TODO(port): implement proper %.14g (choose between %e and %f based on magnitude)
960	                format!("{:.14e}", fval)
961	            };
962	            match file.write_bytes(s.as_bytes()) {
963	                Ok(n) => overall_ok = overall_ok && n == s.len(),
964	                Err(_) => overall_ok = false,
965	            }
966	        } else {
967	            // C: const char *s = luaL_checklstring(L, arg, &l);
968	            // C: status = status && (fwrite(s, sizeof(char), l, f) == l);
969	            let s: Vec<u8> = state.check_arg_string(idx)?;
970	            match file.write_bytes(&s) {
971	                Ok(n) => overall_ok = overall_ok && n == s.len(),
972	                Err(_) => overall_ok = false,
973	            }
974	        }
975	    }
976	
977	    // C: if (status) return 1; else return luaL_fileresult(L, status, NULL);
978	    if overall_ok {
979	        Ok(1) // file handle already at stack top; C returns it on success
980	    } else {
981	        file_result(
982	            state,
983	            false,
984	            None,
985	            io::Error::new(io::ErrorKind::Other, "write error"),
986	        )
987	    }
988	}
