990	/// `io.write(...)`. C: `io_write`.
991	///
992	/// PORT NOTE: routes writes directly through `state.write_output()` rather than
993	/// `g_write(getiofile(IO_OUTPUT))`. The full C path needs typed-userdata access
994	/// to pull `LStream` out of the registry and an interior-mutability split to
995	/// borrow its `LuaFileOps` alongside `&mut LuaState`; both land in Phase B.
996	/// Until then, the only `IO_OUTPUT` ever installed by `luaopen_io` is `stdout`,
997	/// so writing through `write_output` is behaviourally identical for the
998	/// default case and lets `print`/`io.write` share the same sink.
999	pub fn io_write(state: &mut LuaState) -> Result<usize, LuaError> {
1000	    // C: int nargs = lua_gettop(L) - arg;  with arg == 1, so nargs == top().
1001	    let n = state.top();
1002	    for i in 1..=n {
1003	        if state.type_at(i) == LuaType::Number {
1004	            // C: lua_isinteger ? fprintf("%lld", ival) : fprintf("%.14g", fval)
1005	            let s = if state.is_integer(i) {
1006	                let ival = state.to_integer(i).unwrap_or(0);
1007	                format!("{}", ival)
1008	            } else {
1009	                let fval = state.to_number(i).unwrap_or(0.0);
1010	                // TODO(port): proper %.14g (significant-digit) formatting; same
1011	                // gap as g_write — fine for now because integer tables hit the
1012	                // branch above and printf-style float formatting is unused on
1013	                // the common path.
1014	                format!("{:.14e}", fval)
